package ru.memearena.vote.api; import io.swagger.v3.oas.annotations.Operation; import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import ru.memearena.vote.application.VoteService; @RestController @RequestMapping("/api/v1/votes") public class VoteController { private final VoteService service; public VoteController(VoteService service){this.service=service;} @PostMapping @Operation(summary="Submit vote") public ResponseEntity<SubmitVoteResponse> submit(@Valid @RequestBody SubmitVoteRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(service.submit(r.userId(),r.leftMemeId(),r.rightMemeId(),r.winnerMemeId()));} }
